<span class="line"><span style="color:#E5C07B;">o</span><span style="color:#ABB2BF;">.</span><span style="color:#E06C75;">time</span><span style="color:#56B6C2;">=</span><span style="color:#E06C75;">sleepTime</span><span style="color:#ABB2BF;">;</span></span>
